from .errors import PipelineError


class Pipeline:
    """Core pipeline for data processing."""

    def __init__(self):
        self._handlers = {}
        self._process_count = 0
        self._last_priority = None

    def subscribe(self, data_type, handler):
        if data_type not in self._handlers:
            self._handlers[data_type] = []
        self._handlers[data_type].append(handler)

    def process(self, data):
        data_type = data.get("type", "unknown")
        self._process_count += 1
        for handler in self._handlers.get(data_type, []):
            handler(data)

    def has_handlers(self, data_type):
        return len(self._handlers.get(data_type, [])) > 0

    def get_process_count(self):
        return self._process_count

    def get_last_priority(self):
        return self._last_priority

    def process_async(self, data):
        raise NotImplementedError("Use AsyncPipeline")

