from .core import Pipeline


class FilterPipeline(Pipeline):
    """Pipeline that filters data by predicate."""

    def __init__(self, predicate=None, min_priority=0):
        super().__init__()
        self.predicate = predicate or (lambda data: True)
        self.min_priority = min_priority

    def process(self, data):
        if self.predicate(data):
            super().process(data)

