from .core import Pipeline


class AsyncPipeline(Pipeline):
    def __init__(self):
        super().__init__()
        self._queue = []

    def process(self, data):
        self._queue.append(data)

    def flush(self):
        for data in self._queue:
            super().process(data)
        self._queue.clear()

