from .core import Pipeline


class ChainPipeline(Pipeline):
    def __init__(self):
        super().__init__()
        self._chain = []

    def add_to_chain(self, pipeline):
        if not isinstance(pipeline, Pipeline):
            raise TypeError(f"Expected Pipeline, got {type(pipeline).__name__}")
        self._chain.append(pipeline)

    def process(self, data):
        super().process(data)
        for pipeline in self._chain:
            pipeline.process(data)

