from .core import Pipeline


class PipelineRouter:
    def __init__(self):
        self._routes = {}

    def add_route(self, key, pipeline):
        if not isinstance(pipeline, Pipeline):
            raise TypeError(f"Expected Pipeline, got {type(pipeline).__name__}")
        self._routes[key] = pipeline

    def route(self, key, data):
        pipeline = self._routes.get(key)
        if pipeline is None:
            raise KeyError(f"No route for key: {key}")
        pipeline.process(data)

    def broadcast(self, data):
        for pipeline in self._routes.values():
            pipeline.process(data)
